  const gen0: Cell[] = [
    [0, 2], [1, 2], [2, 2],
    [1, 1],
    [0, 0], [1, 0], [2, 0],
  ];
  const next = nextGeneration(gen0);
  const inWindow = next
    .filter(([x, y]) => x >= 0 && x <= 2 && y >= 0 && y <= 2)
    .map(([x, y]) => `${x},${y}`)
    .sort();
  expect(inWindow).toEqual(['0,0', '0,1', '0,2', '2,0', '2,1', '2,2'].sort());
});

