        const ny = y + dy;
        const key = `${nx},${ny}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    const isAlive = alive.has(key);
    if (count === 3 || (count === 2 && isAlive)) {
      const [xStr, yStr] = key.split(',');
      result.push([Number(xStr), Number(yStr)]);
    }
  }

  return result;
}
